"use client";

import { useState } from "react";
import * as stylex from "@stylexjs/stylex";
import { Button } from "@/components/ui/Button/button";
import { Input, Label } from "@/components/ui/Input/input";
import { Text } from "@/components/ui/Text/text";
import { Checkbox } from "@/components/ui/Checkbox/checkbox";
import { Separator } from "@/components/ui/Separator/separator";
import { Card, CardBody } from "@/components/ui/Card/card";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { loginStyles } from "./login-01.styles";

type SocialProvider = {
	provider: string;
	handleClick?: () => void;
};

type Links = {
	forgotPassword?: { label: string; handleClick: () => void };
	signUp?: { label: string; handleClick: () => void };
};

type FormValues = {
	email: string;
	password: string;
	rememberMe: boolean;
};

type Props = PropsWithStylex<{
	title?: string;
	description?: string;
	logo?: React.ReactNode;
	onSubmit?: (values: FormValues) => void;
	socialProviders?: SocialProvider[];
	links?: Links;
}>;

export function Login01({
	title = "Welcome back",
	description = "Sign in to your account to continue",
	logo,
	onSubmit,
	socialProviders,
	links,
	style,
}: Props) {
	const [email, setEmail] = useState("");
	const [password, setPassword] = useState("");
	const [rememberMe, setRememberMe] = useState(false);

	const handleSubmit = (e: React.FormEvent) => {
		e.preventDefault();
		onSubmit?.({ email, password, rememberMe });
	};

	return (
		<div {...stylex.props(loginStyles.container, style)}>
			<Card {...stylex.props(loginStyles.card)}>
				<CardBody {...stylex.props(loginStyles.cardBody)}>
					<div {...stylex.props(loginStyles.header)}>
						{logo && <div {...stylex.props(loginStyles.logo)}>{logo}</div>}
						<Text variant="h3" style={loginStyles.title}>
							{title}
						</Text>
						<Text variant="body2" style={loginStyles.description}>
							{description}
						</Text>
					</div>

					<form
						onSubmit={handleSubmit}
						aria-label="Sign in form"
						{...stylex.props(loginStyles.form)}
					>
						<div {...stylex.props(loginStyles.fieldGroup)}>
							<Label htmlFor="login-email">Email</Label>
							<Input
								id="login-email"
								type="email"
								placeholder="name@example.com"
								value={email}
								onChange={(e) => setEmail(e.target.value)}
								required
								autoComplete="email"
							/>
						</div>

						<div {...stylex.props(loginStyles.fieldGroup)}>
							<Label htmlFor="login-password">Password</Label>
							<Input
								id="login-password"
								type="password"
								placeholder="Enter your password"
								value={password}
								onChange={(e) => setPassword(e.target.value)}
								required
								autoComplete="current-password"
							/>
						</div>

						<div {...stylex.props(loginStyles.checkboxRow)}>
							<label
								htmlFor="remember-me"
								{...stylex.props(loginStyles.checkboxLabel)}
							>
								<Checkbox
									id="remember-me"
									checked={rememberMe}
									onCheckedChange={(checked) =>
										setRememberMe(checked as boolean)
									}
								/>
								Remember me
							</label>
							{links?.forgotPassword && (
								<button
									type="button"
									onClick={links.forgotPassword.handleClick}
									{...stylex.props(loginStyles.forgotLink)}
								>
									{links.forgotPassword.label ?? "Forgot password?"}
								</button>
							)}
						</div>

						<Button type="submit" variant="solid" fullWidth>
							Sign in
						</Button>
					</form>

					{socialProviders && socialProviders.length > 0 && (
						<div {...stylex.props(loginStyles.socialSection)}>
							<Separator label="Or continue with" tone="subtle" />
							<div {...stylex.props(loginStyles.socialButtons)}>
								{socialProviders.map((provider) => (
									<Button
										key={provider.provider}
										variant="outline"
										onClick={provider.handleClick}
										style={loginStyles.socialButton}
									>
										{provider.provider}
									</Button>
								))}
							</div>
						</div>
					)}

					{links?.signUp && (
						<div {...stylex.props(loginStyles.footer)}>
							<Text variant="body2" span>
								Don&apos;t have an account?{" "}
							</Text>
							<button
								type="button"
								onClick={links.signUp.handleClick}
								{...stylex.props(loginStyles.footerLink)}
							>
								{links.signUp.label ?? "Sign up"}
							</button>
						</div>
					)}
				</CardBody>
			</Card>
		</div>
	);
}

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { spacing, fontSize } from "@/lib/theme/tokens.stylex";

export const loginStyles = stylex.create({
	container: {
		display: "flex",
		alignItems: "center",
		justifyContent: "center",
		minHeight: "100vh",
		padding: spacing.medium,
		boxSizing: "border-box",
	},
	card: {
		width: "100%",
		maxWidth: 420,
	},
	cardBody: {
		display: "flex",
		flexDirection: "column",
		gap: spacing.large,
	},
	header: {
		textAlign: "center",
		display: "flex",
		flexDirection: "column",
		alignItems: "center",
		gap: spacing.xsmall,
	},
	logo: {
		marginBottom: spacing.xsmall,
	},
	title: {},
	description: {
		color: theme.contentSecondary,
	},
	form: {
		display: "flex",
		flexDirection: "column",
		gap: spacing.medium,
	},
	fieldGroup: {
		display: "flex",
		flexDirection: "column",
		gap: spacing.small,
	},
	checkboxRow: {
		display: "flex",
		flexDirection: "row",
		alignItems: "center",
		justifyContent: "space-between",
	},
	checkboxLabel: {
		display: "flex",
		flexDirection: "row",
		alignItems: "center",
		gap: spacing.xsmall,
		cursor: "pointer",
		fontSize: fontSize.small,
	},
	forgotLink: {
		background: "none",
		border: "none",
		padding: 0,
		cursor: "pointer",
		color: theme.contentAccent,
		fontSize: fontSize.small,
		fontFamily: "inherit",
		":hover": {
			textDecoration: "underline",
		},
	},
	socialSection: {
		display: "flex",
		flexDirection: "column",
		gap: spacing.small,
	},
	socialButtons: {
		display: "flex",
		flexDirection: "row",
		gap: spacing.small,
	},
	socialButton: {
		flex: 1,
	},
	footer: {
		textAlign: "center",
	},
	footerLink: {
		background: "none",
		border: "none",
		padding: 0,
		cursor: "pointer",
		color: theme.contentAccent,
		fontFamily: "inherit",
		fontSize: fontSize.small,
		":hover": {
			textDecoration: "underline",
		},
	},
});
